"""
MKT Christ Commentary — 2 Chronicles chapters 35–36
Run: python3 scripts/zc-christ-2chronicles-35-36.py

The final two chapters of Chronicles — the culmination of the Davidic narrative:

Ch 35: Josiah's Passover and Death at Megiddo
  - v1-19: The Passover — greatest since Samuel; 49 verses of liturgical exactitude;
    type for Christ as the Passover lamb (1 Cor 5:7); last great OT Passover before new covenant
  - v11: blood-sprinkling by priests → type for Christ's sacrificial blood applied by priestly ministry
  - v13: roasting the lamb as prescribed → the Passover rite fulfilled in Christ (Exod 12:8; John 19:28-36)
  - v18: no Passover like this since Samuel → the pinnacle before the true Passover
  - v20-24: Josiah disguises himself (like Ahab, ch 18) and is killed → the irony of the reforming king's death;
    also echoes Deut 18:15 problem (the greatest prophet-king dies; a greater Moses is needed)
  - v21: Necho as the unexpected voice of divine command → God speaks through pagan kings
  - v25: Jeremiah laments → the pattern of prophetic mourning for Israel's fallen king

Ch 36: The Collapse of the Davidic Kingdom
  - v1-13: Four failed kings in rapid succession — the anti-David sequence
  - v14-16: The rejected prophets → type for Christ's rejection (Matt 23:37; Luke 11:47-51)
  - v17-20: The burning of the temple → judgment that Christ reverses in resurrection (John 2:19-21)
  - v21: The land's Sabbath rest → Sabbatical theology; rest the land is given while people are in exile
  - v22-23: Cyrus decree → the open-handed ending; type of the new creation proclamation;
    v23 already present — only writing v1-22 this pass
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

CHRIST = {
  "35": {
    "1": "<p>A direct connection. Josiah keeps the Passover on the fourteenth day of the first month — the precise date of Exod 12:6 (the original Passover) and Num 9:3 (the standardized form). Unlike Hezekiah&rsquo;s Passover kept in the second month (2 Chr 30:2-3, necessitated by Levitical uncleanness), Josiah&rsquo;s is metronomically exact. The calendar precision is the Chronicler&rsquo;s signal that the covenant is being kept <em>exactly</em> as given. Christ the Passover Lamb (1 Cor 5:7) was crucified on the fourteenth of Nisan (John 19:14,31,42) — the same date Josiah inaugurated. The Passover kept <em>on the day</em> reaches its fulfillment in the sacrifice offered <em>on the day</em>.</p>",
    "2": "<p>A shadow. Josiah stationing the priests in their divisions — <em>wayya&lsquo;amîdēm &lsquo;al-miškĕmôtām</em>, &lsquo;he caused them to stand upon their stations&rsquo; — is the royal-priestly coordination that the Passover requires. The king who ensures the priests are positioned mirrors the pattern of Moses (Exod 40:12-15) and Solomon (2 Chr 8:14). In the new covenant, Christ both positions and is the priest: &lsquo;he always lives to make intercession&rsquo; (Heb 7:25), the high priest perpetually at his station before the Father. The encouragement Josiah gives the priests (<em>wayhazzeqêm</em>, &lsquo;he strengthened them&rsquo;) anticipates Christ who equips his priestly people (Eph 4:11-12).</p>",
    "3": "<p>A shadow. Josiah&rsquo;s instruction to the Levites — &lsquo;Put the holy ark in the house that Solomon son of David, king of Israel, built. You need not carry it on your shoulders&rsquo; — releases the Levites from the transportation burden and redirects their service to worship and preparation. The ark at rest is the typological precedent for Hebrews&rsquo; argument: now that the high priest has entered the true sanctuary (Heb 9:11-12), the preparatory carrying work is complete. The Levites can now serve the people in preparation rather than transport. Christ, having carried the burden of atonement to its destination, releases his servants for ministry rather than the carrying of sacred burdens.</p>",
    "4": "<p>A shadow. &lsquo;Prepare yourselves according to your ancestral families and divisions, as prescribed in the writing of David king of Israel and as written in the document of Solomon his son&rsquo; — the coordinated preparation that requires both David&rsquo;s organizational blueprint and Solomon&rsquo;s written instructions. The Passover is prepared <em>according to written authority</em>, not improvised. The written authority behind the Passover points to the written word that governs the new covenant Passover: Christ&rsquo;s command at the Last Supper was immediately transmitted as written apostolic tradition (1 Cor 11:23: &lsquo;I received from the Lord what I also delivered to you&rsquo;). The supper is observed <em>according to writing</em>.</p>",
    "5": "<p>A shadow. &lsquo;Stand in the Holy Place according to the groupings of the ancestral families of your brothers the lay people, and according to the Levitical division of a family&rsquo; — the ordered positioning of priests between the lay people and the sanctuary is the priestly mediation structure of the Passover. Every lay Israelite approaches through a priest; every priest stands at the boundary of the Holy Place. The mediation structure that positions the priest between the people and the divine presence is the type Christ fulfills: &lsquo;there is one mediator between God and men, the man Christ Jesus&rsquo; (1 Tim 2:5). The Levitical positioning is the structural type of the singular mediation of Christ.</p>",
    "6": "<p>A direct connection. &lsquo;Slaughter the Passover offerings, consecrate yourselves, and prepare your brothers so that they may do according to the word of the LORD by Moses&rsquo; — the three-part commission (slaughter, consecrate, prepare) mirrors the three movements of the gospel: sacrifice (Christ&rsquo;s death), sanctification (the Spirit&rsquo;s work), and preparation of the church (apostolic teaching). The command to prepare brothers echoes Deut 16:1-8; the &lsquo;word of the LORD by Moses&rsquo; is the authority structure the Passover operates within. Paul applies the same three movements in 1 Cor 5:7-8: Christ as sacrifice, the church as the unleavened community, the Passover kept in sincerity and truth.</p>",
    "7": "<p>A type. Josiah&rsquo;s personal contribution — 30,000 lambs and young goats for Passover offerings, plus 3,000 cattle — is the royal gift that makes the Passover possible for the people who cannot provide for themselves. The king provides what the lay people need for the covenant meal. Christ provides what no human could supply for the true Passover: &lsquo;Christ, our Passover lamb, has been sacrificed&rsquo; (1 Cor 5:7). The Passover lamb is not the worshipper&rsquo;s contribution but the gift of the one who ensures the feast can occur. Josiah&rsquo;s 30,000 lambs is a vast royal provision that is entirely superseded by the one Lamb who was slain (Rev 5:12).</p>",
    "8": "<p>A shadow. The voluntary contributions of Josiah&rsquo;s officials — Hilkiah, Zechariah, and Jehiel giving 2,600 lambs and 300 cattle — is the willing generosity of the priestly community that supplements the royal provision. The leaders who give willingly out of their own resources for the community feast mirror the apostolic generosity in Acts 4:34-35 (those with resources selling and distributing) and 2 Cor 8:2-3 (the Macedonian churches giving &lsquo;beyond their ability&rsquo; for others). The Passover feast that depends on the generosity of leaders pointing toward the community that gathers at Christ&rsquo;s table because those entrusted with resources have given for the benefit of all.</p>",
    "9": "<p>A shadow. The additional Levitical contributions — 5,000 Passover offerings and 500 cattle — represent the Levites as community whose leaders also contribute. The layered generosity (king → officials → Levites) mirrors the NT pattern of giving: from the highest (the apostolic foundation) through the leadership to the whole community. The cumulative total of contributions for one Passover — thousands of animals from multiple community sectors — is the shadow of the one perfect sacrifice that Christ makes once for all (Heb 9:26-28: &lsquo;to put away sin by the sacrifice of himself...once for all&rsquo;), rendering all subsequent animal-sacrifice contributions permanently unnecessary.</p>",
    "10": "<p>A shadow. &lsquo;When the service had been prepared, the priests stood in their positions and the Levites in their divisions, according to the king&rsquo;s command&rsquo; — the entire liturgical assembly organized and ready at the king&rsquo;s command is the Passover as a coordinated act of obedience. The Passover does not happen spontaneously; it is organized, commanded, and executed. The new covenant gathering for the Lord&rsquo;s Supper follows the same pattern: Paul&rsquo;s instruction to the Corinthians (1 Cor 11:17-34) is explicitly about how it must be &lsquo;prepared&rsquo; — the disorder he condemns is a failure of the coordination that Josiah&rsquo;s Passover models perfectly.</p>",
    "11": "<p>A direct connection. &lsquo;They slaughtered the Passover lambs, and the priests sprinkled the blood received from the Levites&rsquo; — the blood-reception and blood-sprinkling is the central act of the Passover rite. The Levites slaughter; the priests receive the blood; the priests sprinkle. This three-step mediation of the sacrificial blood is the type of Christ&rsquo;s atonement: Christ is both the lamb slaughtered and the high priest who presents the blood (Heb 9:12: &lsquo;he entered once for all into the holy places, not by means of the blood of goats and calves but by means of his own blood, thus securing an eternal redemption&rsquo;). In Christ, the slaughterer, the blood-bearer, and the sprinkler are one person — the mediatory chain collapsed into the one Mediator.</p>",
    "12": "<p>A shadow. The burnt offerings set aside for distribution &lsquo;to give them to the groupings of the ancestral families of the lay people to offer to the LORD, as written in the Book of Moses&rsquo; — the exact distribution of the sacrifice according to written prescription ensures every family group participates. No family is left out; every household has access to the sacrifice through the organized distribution system. In Christ, the distribution of the sacrifice is universal: &lsquo;the grace of God has appeared, bringing salvation for all people&rsquo; (Tit 2:11). The Passover distributed to every family group is the type of the gospel offered to every people group (Rev 5:9: &lsquo;from every tribe and language and people and nation&rsquo;).</p>",
    "13": "<p>A direct connection. &lsquo;They roasted the Passover lambs over the fire as prescribed&rsquo; — the roasting method specified in Exod 12:8-9 (&lsquo;roasted over the fire, with its head, legs, and inner parts&rsquo;; &lsquo;do not eat it raw or boiled in water&rsquo;) is followed exactly. The <em>bāʾēš</em> (in/by fire) method is the prescribed form. The fire-roasting of the Passover lamb anticipates the cross: the lamb that bore the judgment represented by fire (fire as divine judgment throughout the OT: Sodom, the incense of Nadab and Abihu, the test of Elijah). John 19:28-37 reads the crucifixion through Passover lenses: the unbroken bones (Exod 12:46; Num 9:12) fulfilled (John 19:36). The lamb roasted exactly as prescribed is the type of the death that happened exactly as written (Luke 24:44-46).</p>",
    "14": "<p>A shadow. &lsquo;Afterward they prepared for themselves and for the priests, because the priests, the sons of Aaron, were occupied with offering the burnt offerings and the fat portions until night&rsquo; — the Levites serve the priests who are too occupied with the sacrificial ministry to prepare their own portions. The servant-of-the-servant principle: the Levites serve the priests so the priests can serve the people so the people can approach YHWH. The inverted service hierarchy (the lesser serves the greater so the greater can serve the even greater who serve the greatest) is the kingdom pattern that Christ names: &lsquo;whoever would be great among you must be your servant, and whoever would be first among you must be slave of all&rsquo; (Mark 10:43-44).</p>",
    "15": "<p>A shadow. The singers of Asaph in their assigned places &lsquo;according to the command of David, Asaph, Heman, and Jeduthun the king&rsquo;s seer&rsquo; — the Passover is accompanied by prescribed music as the Levitical gatekeepers guard every gate. The Passover feast has a liturgical music tradition; it does not take place in silence. At the Last Supper, Jesus and the disciples &lsquo;sang a hymn&rsquo; before going to the Mount of Olives (Matt 26:30) — almost certainly Pss 114-118, the Hallel, which the Passover seder required. The singers at their stations for Josiah&rsquo;s Passover and the hymn at the end of the Last Supper are the Passover&rsquo;s musical frame, pointing to the praise that surrounds the sacrifice of the true Lamb.</p>",
    "16": "<p>A shadow. &lsquo;So all the service of the LORD was prepared that day for keeping the Passover and offering burnt offerings on the altar of the LORD, according to the command of King Josiah&rsquo; — the completeness formula that signals the Passover has been kept exactly as commanded. The threefold emphasis: all the service, that day, according to command. The precision matters. Paul&rsquo;s formula for the Lord&rsquo;s Supper closes with the same completeness concern: &lsquo;as often as you eat this bread and drink the cup, you proclaim the Lord&rsquo;s death until he comes&rsquo; (1 Cor 11:26). The &lsquo;until he comes&rsquo; is the timeline of the new covenant Passover — kept precisely, repeatedly, until the return of the one who instituted it.</p>",
    "17": "<p>A shadow. &lsquo;The Israelites who were present kept the Passover at that time, and the Feast of Unleavened Bread for seven days&rsquo; — the coupling of Passover with the seven-day Feast of Unleavened Bread is the full liturgical unit (Exod 12:14-20; 13:3-10). The one night of the Passover lamb opens into a week of unleavened bread — the day of sacrifice extends into a season of purification. Paul applies this to the church: &lsquo;let us therefore celebrate the festival, not with the old leaven... but with the unleavened bread of sincerity and truth&rsquo; (1 Cor 5:8). The seven-day season of the church&rsquo;s life is to be lived as the continuation of the Passover — the sacrifice applied to daily existence.</p>",
    "18": "<p>A direct connection. &lsquo;No Passover like this had been kept in Israel since the days of Samuel the prophet. None of the kings of Israel had kept such a Passover as was kept by Josiah&rsquo; — the climactic Passover of the entire Davidic era; nothing like it since the tribal period before the monarchy. This is the peak of Passover observance in the OT — the most complete, most exactly prescribed, most broadly participated feast the covenant people ever kept. It is the final great OT Passover before the exile. The Last Supper is its fulfillment: &lsquo;this is my body... this cup is the new covenant in my blood&rsquo; (Luke 22:19-20). The greatest Passover of the old covenant (Josiah&rsquo;s) gives way to the one feast that renders all future Passover lamb-slaughter unnecessary.</p>",
    "19": "<p>A shadow. &lsquo;This Passover was kept in the eighteenth year of Josiah&rsquo;s reign&rsquo; — the dating formula anchors the greatest Passover in the Davidic chronology. The eighteenth year is the year of the Book of the Law&rsquo;s discovery (2 Chr 34:8) — the Passover grows directly out of the rediscovery of the covenant text. The connection between the found law and the Passover celebration is the pattern of covenant renewal: hear the word → repent → keep the feast. Jesus quotes Scripture throughout his final Passover night (John 13-17 is saturated with OT allusion), and the institution of the Lord&rsquo;s Supper is itself a scriptural interpretation of the Exodus event. The word precedes the feast.</p>",
    "20": "<p>A shadow. &lsquo;After all this, when Josiah had put the temple in order, Neco king of Egypt came up to fight at Carchemish on the Euphrates, and Josiah went out to meet him&rsquo; — the abrupt transition from the greatest Passover to the king&rsquo;s last battle is one of the Bible&rsquo;s most jarring narrative moves. The reforming king who kept the perfect Passover marches to his death. The juxtaposition is the shadow of the Last Supper&rsquo;s own narrative transition: from the Passover meal (Luke 22:14-23) to Gethsemane (Luke 22:39-46) to the arrest. The greatest feast precedes the greatest death in both cases. The Passover and the cross are inseparable.</p>",
    "21": "<p>A revelation of God. Neco&rsquo;s message to Josiah — &lsquo;I am not coming against you today but against the house with which I am at war. God has commanded me to hurry. Stop opposing God, who is with me, so he will not destroy you&rsquo; — is the Egyptian pagan king carrying a genuine divine message that Josiah fails to heed. YHWH&rsquo;s word comes through an unexpected instrument: the enemy king on his way to Carchemish. The same pattern recurs throughout Scripture: Balaam&rsquo;s donkey, Cyrus as YHWH&rsquo;s shepherd (Isa 44:28), Nebuchadnezzar as YHWH&rsquo;s servant (Jer 25:9), and ultimately — the revelation of God speaking through the Gentile instrument that Jesus identifies in Matt 12:42 (the Queen of the South) and Luke 11:31. The word of God is not confined to Israel&rsquo;s official prophets.</p>",
    "22": "<p>A shadow. &lsquo;Nevertheless Josiah did not turn away from him but disguised himself to fight with him. He did not listen to the words of Neco from the mouth of God&rsquo; — Josiah&rsquo;s fatal mistake: the same disguise strategy as Ahab (2 Chr 18:29), and the same failure to receive divine communication through an unexpected channel. The parallels between Josiah and Ahab are deliberate: both disguised themselves for a battle they should not have fought; both died from archers&rsquo; arrows in that battle. The righteous king who makes one fatal blunder shadows the human need for a king who will &lsquo;not rely on his own understanding&rsquo; (Prov 3:5). The one king who never failed to hear the Father — even when the message came through unexpected channels — is Christ (John 5:19: &lsquo;the Son can do nothing of his own accord, but only what he sees the Father doing&rsquo;).</p>",
    "23": "<p>A shadow. &lsquo;The archers shot King Josiah, and the king said to his servants, &ldquo;Take me away, for I am badly wounded&rdquo;&rsquo; — the arrow that struck Josiah mirrors the arrow that killed Ahab (2 Chr 18:33-34: a randomly-aimed arrow that found its target). But with a crucial difference: Ahab&rsquo;s death was YHWH&rsquo;s judgment on the wicked; Josiah&rsquo;s death is the suffering of the righteous king who made one fatal error of judgment. The righteous king who suffers mortal wounds in a battle he misjudged is the type of Christ, who — in an entirely different register — voluntarily entered the arena of judgment and bore wounds he did not deserve. The wounding of the king at the moment of his greatest strength is a shadow of the suffering of the innocent.</p>",
    "24": "<p>A shadow. Josiah&rsquo;s servants transferring him from his war chariot to his second chariot and bringing him to Jerusalem, where he died — and the whole of Judah and Jerusalem mourning for him — is the transport of the dying king back to the royal city. The king who cannot save himself, who must be carried by others, who dies in the city of YHWH&rsquo;s house — this is the shadow of the one who was taken down from the cross and buried in Jerusalem. Joseph of Arimathea&rsquo;s transport of Jesus&rsquo; body (John 19:38-42) is the same movement: from the place of death, carried by servants, to a burial in the holy city. Josiah&rsquo;s tomb and Jesus&rsquo; tomb are both in Jerusalem; one opened permanently on the third day.</p>",
    "25": "<p>A direct connection. &lsquo;Jeremiah lamented for Josiah, and all the male and female singers have spoken of Josiah in their laments to this day&rsquo; — the prophetic lament for the fallen righteous king becomes a liturgical tradition that endures across generations. The lament for the lost king is one of the OT&rsquo;s most persistent prophetic forms. Zechariah 12:10-11 explicitly draws on the Megiddo mourning (&lsquo;as one mourns for an only son... as one mourns over the firstborn... as the mourning of Hadad-rimmon in the plain of Megiddo&rsquo;) as the type of the mourning that will occur when Israel looks on &lsquo;him whom they have pierced.&rsquo; The lament for Josiah becomes the prophetic template for the lament at the piercing of Christ — the mourning that will flow when the ultimate Shepherd-King is recognized.</p>",
    "26": "<p>A shadow. &lsquo;The rest of the acts of Josiah and his faithful deeds, as written in the law of the LORD&rsquo; — the standard closing formula, but with a distinctive addition: his <em>ḥasādāyw</em> (&lsquo;his acts of faithful covenant loyalty&rsquo;) <em>as written in the law of the LORD</em>. Josiah&rsquo;s acts of covenant loyalty are evaluated against the written Torah — his faithfulness is measured by the written word. The standard Christ sets for judgment is himself (John 12:48: &lsquo;the word that I have spoken will judge him on the last day&rsquo;) and the fulfillment of the written word (Matt 5:17: &lsquo;do not think that I have come to abolish the Law or the Prophets; I have not come to abolish them but to fulfill them&rsquo;). The written law is the standard; Christ is its fulfillment.</p>",
    "27": "<p>A shadow. &lsquo;His acts, first and last, are recorded in the Book of the Kings of Israel and Judah&rsquo; — the final closing formula for Josiah; after him come four failed kings in rapid succession (ch 36) before the exile. Josiah is the last righteous king; his record is closed. The pattern of the Chronicles is: the righteous king whose work is complete, followed by the collapse. Christ is the one whose works are recorded not in Chronicles but in the Gospels — and John 21:25 says the record is necessarily selective: &lsquo;were every one of them to be written, I suppose that the world itself could not contain the books.&rsquo; The chronicler closes with Josiah; the evangelist opens with the one whose acts exceed all record.</p>"
  },
  "36": {
    "1": "<p>A shadow. &lsquo;The people of the land took Jehoahaz son of Josiah and made him king in his father&rsquo;s place in Jerusalem&rsquo; — after Josiah&rsquo;s death, the people bypass the normal succession and install their chosen son (bypassing the older Eliakim; cf. 2 Kgs 23:31). Popular kingship-installation in the absence of a divine oracle is the kingdom&rsquo;s final chapter without divine direction. The contrast with the Davidic line at its beginning: &lsquo;the LORD said to Samuel, &ldquo;I have chosen him&rdquo;&rsquo; (1 Sam 16:12). The people choosing their own king, rather than waiting for YHWH&rsquo;s choice, is the shadow of every generation that prefers its own selection over the anointed one. Christ is the Father&rsquo;s choice, announced at baptism: &lsquo;this is my beloved Son, with whom I am well pleased&rsquo; (Matt 3:17).</p>",
    "2": "<p>A shadow. Jehoahaz reigns three months — the briefest of brief reigns, insufficient for any substantive policy or reform. Three months in, then Egypt ends it. The rapidity of the collapse after Josiah&rsquo;s death mirrors the pattern of the disciples after the crucifixion: scattered within hours (Mark 14:50), hiding behind locked doors (John 20:19). The three-month reign of Jehoahaz is less than the three days of the crucifixion. What the disciples could not sustain for three days, Jehoahaz could not sustain for three months. The short-lived successor who cannot maintain the inheritance is the type of all successors to Josiah until the one who does not merely succeed but fulfills.</p>",
    "3": "<p>A shadow. Egypt imposes a tribute of one hundred talents of silver and one talent of gold — the covenant people paying tribute to Egypt, the great type of bondage. The return to Egypt-tribute is the shadow of covenant slavery: the people who were redeemed from Egypt now pay Egypt again. Every tribute imposed by Gentile powers on Judah echoes the Egypt-bondage pattern that the Exodus was meant to terminate permanently. Christ pays the tribute that could not be owed — the price for sin that no coin could cover. But he also liberates from the tribute-paying condition: &lsquo;you were ransomed from the futile ways inherited from your forefathers, not with perishable things such as silver or gold, but with the precious blood of Christ&rsquo; (1 Pet 1:18-19). The silver-and-gold tribute gives way to the blood-ransom.</p>",
    "4": "<p>A shadow. Egypt renames Eliakim as Jehoiakim — a pagan overlord renaming the Davidic king is the shadow of colonized identity, the covenant king re-branded by the empire. The name-change from &lsquo;God establishes&rsquo; (Eliakim) to &lsquo;YHWH establishes&rsquo; (Jehoiakim) is apparently a concession that preserves YHWH&rsquo;s name but on Egypt&rsquo;s terms. The colonized covenant identity is what Christ reverses: he gives his followers a new name (Rev 2:17: &lsquo;a new name that no one knows except the one who receives it&rsquo;), a name not imposed by empire but given by the Father, the identity that no colonial power can rename.</p>",
    "5": "<p>A shadow. Jehoiakim&rsquo;s eleven-year reign — the longest in the final four kings — is characterized entirely by &lsquo;he did what was evil in the sight of the LORD his God.&rsquo; The king who reigns the longest of the final four is also the least faithful. The Chronicler does not detail the evil; the verdict is the whole record. The contrast with Christ: the one whose reign is &lsquo;forever and ever&rsquo; (Rev 11:15) does &lsquo;what is right and just&rsquo; (Isa 9:7). The eleven years of Jehoiakim&rsquo;s reign &lsquo;doing evil&rsquo; is the anti-reign that Christ&rsquo;s eternal righteous rule answers.</p>",
    "6": "<p>A shadow. Nebuchadnezzar binds Jehoiakim in bronze chains to take him to Babylon — the Davidic king in chains, led away by the Babylonian overlord. The binding of the king is the anti-anointing: what was promised to David (&lsquo;your house and your kingdom will endure forever,&rsquo; 2 Sam 7:16) appears to be ending in chains and exile. The bound king is the type of the bound God: Christ in Gethsemane is bound and led away (John 18:12: &lsquo;they bound him and led him first to Annas&rsquo;). But the binding of the Son of God is the decisive un-binding of humanity from sin: &lsquo;if the Son sets you free, you will be free indeed&rsquo; (John 8:36). The chains on the Davidic king give way to the chains on the divine king whose captivity is voluntary and redemptive.</p>",
    "7": "<p>A direct connection. &lsquo;Nebuchadnezzar also carried some of the vessels of the LORD&rsquo;s house to Babylon and placed them in his palace in Babylon&rsquo; — the sacred temple vessels transferred to the pagan palace treasury is one of the OT&rsquo;s most theologically loaded acts. Daniel 5 makes these very vessels the focal point of Belshazzar&rsquo;s sacrilege — when they are used for the pagan feast, the divine judgment-writing appears on the wall. The vessels represent the holiness of YHWH housed in Babylon. Christ himself is the vessel of divine holiness in a world of sacrilege: &lsquo;in him the whole fullness of deity dwells bodily&rsquo; (Col 2:9). The sacred vessel in the hostile palace is the type of God present in a world that treats him as a trophy.</p>",
    "8": "<p>A shadow. &lsquo;The rest of the acts of Jehoiakim and the abominations he committed, and what was found against him, are recorded in the Book of the Kings of Israel and Judah&rsquo; — the closing formula for Jehoiakim adds an unusual element: &lsquo;what was found against him&rsquo; (<em>wehannimṣāʾ &lsquo;ālāyw</em>). The phrase suggests a formal indictment; something was discovered that formed part of the legal case against him. This language of found evidence points toward the judgment scene: Rev 20:12-13 describes books opened and people judged &lsquo;according to what they had done.&rsquo; Jehoiakim&rsquo;s &lsquo;what was found against him&rsquo; is the precursor of the divine ledger; Christ is the advocate who stands before the same ledger on behalf of those he represents (1 John 2:1).</p>",
    "9": "<p>A shadow. Jehoiachin reigns three months and ten days — even briefer than Jehoahaz&rsquo; three months. The shrinking reign-lengths (11 years → 3 months → 3 months and 10 days → 11 years) tell the story of the kingdom&rsquo;s accelerating collapse. The Davidic line, once measured in decades and centuries, is now measured in days. The trajectory is the darkness before dawn: the shortest reigns come just before the exile, but the exile ends with Cyrus&rsquo; decree — and ultimately with a king whose reign never ends (Luke 1:33: &lsquo;of his kingdom there will be no end&rsquo;). The three months and ten days of Jehoiachin&rsquo;s reign is less than the time between Christ&rsquo;s resurrection and ascension — yet in those days, a kingdom was established that still stands.</p>",
    "10": "<p>A shadow. &lsquo;In the spring of the year, King Nebuchadnezzar sent and brought him to Babylon along with the precious vessels of the house of the LORD&rsquo; — Jehoiachin&rsquo;s exile in &lsquo;the spring of the year&rsquo; (<em>lĕtěšûḇat haššānāh</em>, &lsquo;at the return of the year&rsquo;, the spring military season) takes both the king and the remaining temple vessels. The spring is when kings go to war (2 Sam 11:1) — but here it is when the Davidic king goes into exile. The Spring that should be victory becomes the spring of defeat. The reversal that Christ brings: the spring of his death and resurrection — the Passover season — reverses the spring of defeat into the spring of permanent victory. The season of exile becomes the season of new creation.</p>",
    "11": "<p>A shadow. Zedekiah — the last king, installed by Nebuchadnezzar himself — reigns eleven years. The Babylonian-installed king of Judah is the nadir of the Davidic dynasty: the king who rules by the permission of the exile power rather than by YHWH&rsquo;s anointing. The king who rules by imperial permission is the type of all authority that is delegated rather than inherent. Christ&rsquo;s authority is not delegated by empire: &lsquo;all authority in heaven and on earth has been given to me&rsquo; (Matt 28:18) — given by the Father, not by Babylon. The emperor-permitted king and the Father-authorized king stand at opposite poles of the authority question.</p>",
    "12": "<p>A shadow. &lsquo;He did what was evil in the sight of the LORD his God. He did not humble himself before Jeremiah the prophet, who spoke from the mouth of the LORD&rsquo; — Zedekiah&rsquo;s specific failure is the failure to humble himself before the prophetic word. The verb <em>niḵnaʿ</em> (&lsquo;to humble oneself&rsquo;) is the Chronicler&rsquo;s key covenant term: Josiah humbled himself (2 Chr 34:27) and was blessed; Zedekiah refused and fell. The unwillingness to bow before the divine word is the core of human rebellion. Christ embodies the perfect humility: &lsquo;though he was in the form of God... he humbled himself by becoming obedient to the point of death&rsquo; (Phil 2:6-8). The self-humbling that Zedekiah refused, Christ enacted absolutely.</p>",
    "13": "<p>A shadow. &lsquo;He also rebelled against King Nebuchadnezzar, who had made him swear by God. He stiffened his neck and hardened his heart against turning to the LORD, the God of Israel&rsquo; — the two rebellions: against the human overlord (breaking the sworn oath) and against YHWH (stiffened neck). The <em>hiqšāh &lsquo;ōrep</em> (&lsquo;he stiffened the neck&rsquo;) is the Exodus vocabulary of hardening (Exod 32:9: &lsquo;a stiff-necked people&rsquo;). The last Davidic king repeats the sin of the wilderness generation. Stephen&rsquo;s sermon names this same pattern: &lsquo;you stiff-necked people... you always resist the Holy Spirit. As your fathers did, so do you&rsquo; (Acts 7:51). The stiff-necked king is the type of the generation that finally crucifies the Son.</p>",
    "14": "<p>A shadow. &lsquo;Moreover, all the leading priests and the people greatly multiplied their unfaithfulness, following all the abominations of the nations, and they polluted the house of the LORD that he had made holy in Jerusalem&rsquo; — the collective corruption: priests, leaders, and people together polluting the sacred space. The pollution of the temple is the act that makes the exile inevitable (Jer 7:12-15: &lsquo;what I did to Shiloh&rsquo;). Jesus&rsquo; temple cleansing (Matt 21:12-13; John 2:14-17) is the reversal: rather than polluting, he purifies. His body is the new temple (John 2:21) that cannot be polluted by human unfaithfulness — &lsquo;holy, innocent, unstained, separated from sinners&rsquo; (Heb 7:26). The priests who polluted the old temple give way to the High Priest who consecrates the new.</p>",
    "15": "<p>A direct connection. &lsquo;The LORD, the God of their fathers, sent word to them persistently through his messengers because he had compassion on his people and on his dwelling place&rsquo; — the divine persistence in sending messengers is grounded in divine compassion (<em>raḥam</em>), not merely in covenant obligation. YHWH sends prophets not because he must but because he loves. Jesus quotes this exact pattern in the parable of the tenants (Matt 21:33-46; Mark 12:1-12; Luke 20:9-19): &lsquo;he sent his servants... he sent other servants... finally he sent his son.&rsquo; The persistent sending that 2 Chr 36:15 narrates is the structural backbone of the parable. The vineyard owner&rsquo;s compassion that keeps sending messengers until the Son himself is sent is the same compassion the Chronicler attributes to YHWH here.</p>",
    "16": "<p>A direct connection. &lsquo;But they kept mocking the messengers of God, despising his words and scoffing at his prophets, until the wrath of the LORD rose against his people, until there was no remedy&rsquo; — the triple rejection: mocking the messengers, despising the words, scoffing at the prophets. Jesus quotes this pattern explicitly: &lsquo;Jerusalem, Jerusalem, you who kill the prophets and stone those who are sent to you&rsquo; (Matt 23:37; Luke 13:34). The &lsquo;no remedy&rsquo; (<em>ʿad lĕʾên marpēʾ</em>) is the diagnosis of a condition that has passed the point of prophylactic possibility — judgment is now inevitable. But what has &lsquo;no remedy&rsquo; in the covenant of law finds remedy in the covenant of grace: the death that was irreversible for the covenant people becomes reversible through the resurrection. Christ is the &lsquo;remedy&rsquo; where there was none.</p>",
    "17": "<p>A shadow. &lsquo;Therefore he brought against them the king of the Chaldeans, who killed their young men with the sword in the house of their sanctuary and had no compassion on young man or virgin, old man or aged&rsquo; — the particular horror of the Babylonian assault: killing within the sanctuary, with no discrimination of age or gender. The sanctuary that was YHWH&rsquo;s dwelling became the site of slaughter. The absence of compassion (<em>lōʾ ḥāmal</em>, &lsquo;he did not spare&rsquo;) mirrors the divine judgment language of Ezekiel: &lsquo;my eye will not spare, and I will have no pity&rsquo; (Ezek 7:4). YHWH gave his people into the hand of one who would show them no mercy — but Christ stands as the one who, being given into the hand of the merciless, absorbed the judgment so that the people of God receive mercy instead of the Babylonian sword.</p>",
    "18": "<p>A shadow. The temple vessels carried to Babylon — &lsquo;all the vessels of the house of God, great and small, and the treasures of the house of the LORD and the treasures of the king and his princes, all these he brought to Babylon&rsquo; — is the complete stripping of the sanctuary. Every sacred object, every royal treasure, taken by the empire. The despoiled temple is the type of the despoiled Christ: &lsquo;they stripped him and put a scarlet robe on him&rsquo; (Matt 27:28); the soldiers divided his garments (John 19:23-24, fulfilling Ps 22:18). The stripping of the sanctuary and the stripping of the Son are both the removal of the sacred by the profane — but what Babylon carried to its palace, Christ carried to his resurrection. The vessels returned (Ezra 1:7-11); the garments were not needed again.</p>",
    "19": "<p>A shadow. &lsquo;They burned the house of God and broke down the wall of Jerusalem. They burned all its palaces with fire and destroyed all its precious vessels&rsquo; — the complete destruction: the temple burned, the walls broken, the palaces consumed, the sacred objects destroyed. The burning of YHWH&rsquo;s house is the nadir of the Davidic narrative — from Solomon&rsquo;s glorious dedication (2 Chr 5-7) to ash. Jesus predicts the same event for the second temple: &lsquo;there will not be left here one stone upon another that will not be thrown down&rsquo; (Matt 24:2). The destruction of the temple is the sign of the end of the old covenant order — the burning of the Solomonic temple points to the destruction of the Herodian temple, which in turn points to the one who replaces the temple (John 4:21-24).</p>",
    "20": "<p>A shadow. &lsquo;He took into exile in Babylon those who had escaped from the sword. They became servants to him and to his sons until the establishment of the kingdom of Persia&rsquo; — the covenant people as Babylonian servants &lsquo;until the establishment of the kingdom of Persia.&rsquo; The time-limit is built into the exile: &lsquo;until&rsquo; — not permanent servitude but bounded bondage. The &lsquo;until&rsquo; is Daniel&rsquo;s seventy years (Dan 9:2, drawn from Jer 25:11-12), and the political change of masters (Persia replacing Babylon) is YHWH&rsquo;s instrument for the restoration. The bounded bondage points to Christ&rsquo;s descent into death: not permanent death but bounded — &lsquo;until the third day&rsquo; (Matt 16:21; 17:23; 20:19). The resurrection is the &lsquo;until&rsquo; point of death&rsquo;s hold.</p>",
    "21": "<p>A direct connection. &lsquo;This fulfilled the word of the LORD spoken through Jeremiah, until the land had enjoyed its Sabbaths. All the days of its desolation it rested, until seventy years were completed&rsquo; — the exile as Sabbath rest for the land is the Levitical theology of Lev 26:34-35 enacted: the land gets the Sabbath rests it was denied when Israel failed to observe the Jubilee and Sabbatical years. The land&rsquo;s enforced rest is a shadow of the Sabbath rest that remains for the people of God (Heb 4:9-11: &lsquo;there remains a Sabbath rest for the people of God&rsquo;). The desolation that gives the land its rest points to the death that gives humanity its permanent rest — the exile&rsquo;s enforced Sabbath is a dark foreshadowing of the rest that Christ&rsquo;s death secures.</p>",
    "22": "<p>A direct connection. &lsquo;Now in the first year of Cyrus king of Persia, in order to fulfill the word of the LORD spoken through Jeremiah, the LORD stirred up the spirit of Cyrus king of Persia to make a proclamation throughout all his kingdom and to put it in writing&rsquo; — the three convergences: the prophetic word of Jeremiah (seventy years), the anointing of Cyrus named by Isaiah (Isa 44:28; 45:1: &lsquo;who says of Cyrus, &ldquo;He is my shepherd&rdquo;... thus says the LORD to his anointed, to Cyrus&rsquo;), and YHWH&rsquo;s stirring of the pagan king&rsquo;s spirit. The first-year declaration of Cyrus is the type of Pentecost: &lsquo;the spirit stirred up&rsquo; → proclamation throughout all the kingdom → written and spoken simultaneously. The Spirit that &lsquo;stirred up&rsquo; Cyrus is the same Spirit poured out at Pentecost to drive the proclamation of the greater liberation.</p>"
  }
}

def main():
    existing = load_comm('mkt-christ', '2chronicles')
    merge_comm(existing, CHRIST)
    save_comm('mkt-christ', '2chronicles', existing)
    total = sum(len(vv) for vv in CHRIST.values())
    print(f'2Chronicles 35-36 mkt-christ written ({total} new entries: ch35={len(CHRIST["35"])}, ch36={len(CHRIST["36"])}).')

if __name__ == '__main__':
    main()
